var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"3종만큼은 나타나지 않기를 바랐는데.","JPN":"第3種だけは現れないことを願っていたのだが。","ENG":"I really hoped a Category 3 wouldn't appear...","TWN":"真希望不要遇到3類侵蝕體。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"하지만…… 저걸 잡으면 너에게 어울리는 옷을 만들 수 있겠어.","JPN":"しかし……あれをやっつければ、汝にぴったりの服を作れそうだ。","ENG":"But... I should be able to make something that fits you with its material.","TWN":"但是……如果能逮到它，我就能做出適合你的衣服。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그럼 오히려 좋은 일이군요.","JPN":"それは好都合ですね。","ENG":"Then this must be a good thing.","TWN":"那反而是好事呢。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"당주님이 느끼던 이 스산한 기운이 저 침식체가 내뿜는 냉기였다니.","JPN":"当主が感じていたこの冷たい気配が、あの侵食体から出る冷気だったとは。","ENG":"I did not expect the chilling energy that Lady Nanahara felt to be the cold air that the C.O. released.","TWN":"堂主感受到的這股寒氣，原來是這個侵蝕體發出來的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그래. 저 녀석에게서 재료를 채집하면 좋은 마법을 담을 수 있을 거야.","JPN":"ああ。あいつから材料を採集すれば、質のいい魔法を込められるだろう。","ENG":"Yeah. If we collect some material from that one, I'll be able to add some special magic.","TWN":"沒錯，從這傢伙身上收集材料的話，就添加很棒的魔法。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"아까 네 몸의 열을 식혀줬던 레모네이드처럼, 냉기 마법을 넣을 수 있을지도 모르고.","JPN":"さっき汝の体の熱を冷やしたレモネードのように、冷気魔法を入れることができるかもしれない。","ENG":"I might be able to add a type of cold magic, similar to the lemonade that cooled you down earlier.","TWN":"就像剛才那杯讓你降溫的檸檬水一樣，或許可以加入寒氣魔法。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"결계 안쪽에는 별의별 놈들이 있기는 하지만, 이렇게 딱 맞게 나타날 줄이야.","JPN":"結界の内側には様々な奴らがいるが、こうもピッタリな奴が現れるとはな。","ENG":"There are all sorts of C.O.s inside the barrier, but I didn't think we'd run into something so perfect for the situation.","TWN":"結界裡面什麼樣的傢伙都有，但沒想到這傢伙出現的時機剛剛好。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"네 말대로 오히려 좋은 상황인 거지.","JPN":"汝の言うとおり、まさに好都合と言える。","ENG":"So it definitely is a good thing, like you said.","TWN":"你說得對，這的確是一個好機會。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"무사히 처리한다면 말이지.","JPN":"無事にやっつけることができたら、だが。","ENG":"That is, if we can take care of it safely.","TWN":"如果我們能順利解決它的話。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹.","JPN":"にゃあ。","ENG":"Meow.","TWN":"喵。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_CAT_START"},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그래 그래. 네 말도 옳아.","JPN":"よし、よし。わかっている。","ENG":"Yeah, yeah. You're right.","TWN":"沒錯，你說的對。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이면 세계에선 무슨 일이 일어날지 알 수 없으니 조심하는 게 맞지.","JPN":"裏世界では何事が起きるかわからない、気をつけるに越したことはない。","ENG":"We have to watch out since we never know what's going to happen in Counterside.","TWN":"在異界中，誰也不知道會發生什麼，謹慎一點總是好的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"아직 녀석이 우릴 발견하지 못한 것 같습니다.","JPN":"まだ奴は私たちに気付いていないようです。","ENG":"It looks like it has not found us yet.","TWN":"看來那傢伙還沒有發現我們。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"주위로 다른 침식체들도 함께 있어. 정면으로 돌파해야 할까요?","JPN":"周りに他の侵食体も一緒にいるわ。正面から突破した方がいいのでしょうか。","ENG":"There are other C.O.s near it. Should we go directly in?","TWN":"周圍還有其他侵蝕體。我們要發動正面攻擊嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이곳의 침식체는 3종이라고 해도 나랑 에블린이 힘을 합치면 잡는 정도야.","JPN":"ここの侵食体は、第3種と言っても妾とエヴリンが力を合わせればやっつけられる程度だ。","ENG":"Evelyn and I are enough to kill the C.O.s in here, even if it's a Category 3.","TWN":"就算這裡的侵蝕體是3類的，但要是我和伊芙琳聯手也能應付。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"동생이 검 휘두르는 걸 보니까 쉽게 상대할 수 있을 것 같은데?","JPN":"妹の刀さばきからすれば、相手にするのは難しくなさそうだが。","ENG":"And from the looks of how your little sister swung her sword around, I think she can easily handle it.","TWN":"看你妹妹揮劍的樣子，應該能輕鬆應付吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇다고 해도 결국 3종은 3종.","JPN":"仮にそうだとしても、第3種は第3種。","ENG":"It is still a Category 3.","TWN":"話雖如此，但畢竟是3類。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"세 분 모두 방심은 금물입니다.","JPN":"三人とも、油断は禁物です。","ENG":"No one should lower their guard.","TWN":"我們三個都不能掉以輕心。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그건 맞는 소리지만, 계속 여기서 기회만 보고 있을 순 없어.","JPN":"だが、ずっとここでチャンスを狙っているわけにもいかないぞ。","ENG":"You're right, but we can't just sit around here forever.","TWN":"你說的對，但也不能一直在這裡等待機會。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"때를 기다리고 있습니다.","JPN":"時を待っているのです。","ENG":"I am waiting for the right time.","TWN":"我在等待時機。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"3종 침식체 주위로 다른 침식체들이 모이고 있어요.","JPN":"第3種侵食体の周りに、他の侵食体が集まってきています。","ENG":"Other C.O.s are gathering around the Category 3.","TWN":"其他侵蝕體正聚集到3類侵蝕體的周圍。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어느 정도 모였을 때 저들을 격파한다면 당분간 이 일대는 안전할 겁니다.","JPN":"ある程度集まってからあれらを撃破すれば、しばらくこの辺りは安全になるでしょう。","ENG":"If we were to vanquish them when they are grouped together, it should leave this area safe for the foreseeable future.","TWN":"若我們能在它們聚集到一定程度時消滅它們，這一帶就會暫時很安全。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"라우라 님이 만들 의상에 도움이 되는 재료라면, 이 치나츠.","JPN":"ラウラ様が作る衣装に役立つ材料でしたら、この千夏。","ENG":"If it is material that could help you make the costume,","TWN":"若這是蘿拉製作衣服所需的材料，"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"진심을 다해 보조하겠습니다.","JPN":"全力でお助けします。","ENG":"I, Chinatsu, will do my best to assist you.","TWN":"那麼千夏會全力協助。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유, 할 수 있지? 다치면 안 돼?","JPN":"千冬、できるわね？　怪我してはダメよ？","ENG":"Chifuyu. You can handle it, right? You better not get hurt.","TWN":"千冬，你沒問題吧？不要受傷喔？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"물론입니다. 당주님.","JPN":"もちろんです、当主。","ENG":"Of course, my lady.","TWN":"當然，堂主。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"제가 정면에서 녀석들을 상대하겠습니다. 라우라 공은 보조를 부탁드립니다.","JPN":"私が正面から奴らを相手します。ラウラ殿は補助をお願いいたします。","ENG":"I will fight them head-on. I would like to ask for your assistance, Dame Laura.","TWN":"我會從正面攻擊那些傢伙，請蘿拉掩護我。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};